import React from 'react';
import { useNavigate } from 'react-router-dom';
import './Home.css';

function Home() {
  const navigate = useNavigate();

  const handleGo = () => {
    navigate('/images');
  };

  return (
    <div className="home-container">
      <div className="home-card">
        <h1>Welcome to the Image Annotation Tool</h1>
        <p>This tool helps you label images with bounding boxes, polygons, ellipses, and more.</p>
        <p style={{ textAlign: 'left' }}>
          <strong>Steps to get started:</strong>
          <ol>
            <li>Click the button below to create a new task and add label classes.</li>
            <li>Upload your images.</li>
            <li>Start annotating!</li>
          </ol>
        </p>
        <button onClick={handleGo}>Create/Upload Images</button>
      </div>
    </div>
  );
}

export default Home;
